script:
frappe.ui.form.on("Hostel Admission", {
    refresh(frm) {
        if (!frm.is_new() && frm.doc.admission_status === "Checked In") {
            frm.add_custom_button("Mark Check-Out", function () {
                frappe.new_doc("Hostel Check-Out", {
                    student: frm.doc.student,
                    hostel_admission: frm.doc.name,
                    hostel: frm.doc.hostel,
                    hostel_block: frm.doc.hostel_block,
                    hostel_room: frm.doc.hostel_room
                });
            }, "Create");
        }
    }
});
